function.body:
-- Logistice
    v_ResultStr VARCHAR2(2000):='';
    v_Message VARCHAR2(2000):='';
    v_Result NUMBER:=1; -- 0=failure
    v_Record_ID VARCHAR2(32);
    v_User_ID VARCHAR2(32):='0';
    v_Done CHAR(1):='N';

    TYPE RECORD IS REF CURSOR;
    Cur_Parameter RECORD;
    Cur_Bpartner RECORD;
    Cur_Record RECORD;
    Cur_RecordValid RECORD;

BEGIN

    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || P_Instance_ID);
    v_ResultStr:='PInstanceNotFound';
    AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'Y', NULL, NULL);

    BEGIN --BODY

        -- Get Parameters
        v_ResultStr:='ReadingParameters';
        FOR Cur_Parameter IN (
            SELECT i.Record_ID, i.AD_User_ID, p.ParameterName, p.P_String, p.P_Number, p.P_Date
            FROM AD_PInstance i
                LEFT JOIN AD_PInstance_Para p ON i.AD_PInstance_ID = p.AD_PInstance_ID
            WHERE i.AD_PInstance_ID = P_Instance_ID
            ORDER BY p.SeqNo
        ) LOOP
            v_Record_ID := Cur_Parameter.Record_ID;
            v_User_ID := Cur_Parameter.AD_User_ID;
        END LOOP; -- Get Parameter

        SELECT * INTO Cur_Record FROM sdc_debitcollect WHERE sdc_debitcollect_id = v_Record_ID;

	SELECT
	    count(*) FILTER (WHERE p.ispaid = 'N') AS count_lines,
	    count(*) FILTER (WHERE dt.ispaid = 'N') AS count_detail,
	    STRING_AGG(DISTINCT COALESCE(p.description, ''), to_char(',')) AS desc_lines,
	    STRING_AGG(DISTINCT COALESCE(dt.description, ''), to_char(',')) AS desc_detail INTO Cur_RecordValid
	FROM
	    sdc_dc_propocollect p
	    LEFT JOIN sdc_dc_detail dt ON dt.sdc_dc_propocollect_id = p.sdc_dc_propocollect_id
	WHERE
	    p.sdc_debitcollect_id = v_Record_ID
	    AND p.isreconciled = 'Y';	

        IF Cur_Record.typeload IN ('RPH') AND Cur_RecordValid.count_detail = 0 THEN
            v_Done:='Y';
        END IF;

        IF Cur_Record.typeload NOT IN ('RPH') AND Cur_RecordValid.count_lines = 0 THEN
            v_Done:='Y';
        END IF;

	IF Cur_Record.typeload IN ('RPH') THEN
	    UPDATE
		sdc_dc_propocollect
	    SET
		ispaid = 'Y',
		description = SUBSTRING(two.desc_lines, 1, 2000),
		updated = now()
	    FROM (
		SELECT
		    sdc_dc_propocollect_id,
		    STRING_AGG(DISTINCT COALESCE(description, ''), to_char(',')) AS desc_lines,
		    count(*) FILTER (WHERE ispaid = 'N') AS count_lines
		FROM
		    sdc_dc_detail
		WHERE
		    sdc_debitcollect_id = v_Record_ID
		GROUP BY
		    sdc_dc_propocollect_id) two
	WHERE
	    sdc_dc_propocollect.sdc_dc_propocollect_id = two.sdc_dc_propocollect_id
		AND two.count_lines = 0;

	END IF;

	UPDATE
	    sdc_debitcollect
	SET
	    status = 'P',
	    updated = now(),
	    description = SUBSTRING(TRIM(COALESCE(description, '')) || CHR(13) || CHR(10) || CASE WHEN Cur_Record.typeload IN ('RPH') THEN
		    Cur_RecordValid.desc_detail
		ELSE
		    Cur_RecordValid.desc_lines
		END, 1, 2000)
	WHERE
	    sdc_debitcollect_id = v_Record_ID
	    AND v_Done = 'Y';

	DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message);
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', v_Result, v_Message);

        RETURN;
    END; --BODY

        EXCEPTION WHEN OTHERS THEN
        v_ResultStr:= '@ERROR=' || SQLERRM;
	DBMS_OUTPUT.PUT_LINE( v_ResultStr);
        ROLLBACK;
        AD_UPDATE_PINSTANCE(P_Instance_ID, NULL, 'N', 0, v_ResultStr);
END SDC_VALID_PAYMENTS
